css:
@page {
  size: A4;
  margin: 12mm 12mm 12mm;
}

.print-format {
  padding: 0 !important;
}

.print-format,
.print-format * {
  box-sizing: border-box;
}

:root {
  --rt-accent: #9a7b53;
  --rt-border: #eadfce;
  --rt-soft-border: #efe5d6;
  --rt-bg: #fffdf9;
  --rt-bg-soft: #fcfaf6;
  --rt-bg-total: #f8f1e5;
  --rt-text: #1f2937;
  --rt-muted: #6b6258;
}

.rt-print {
  color: #1f2937;
  color: var(--rt-text, #1f2937);
  font-size: 10px;
  line-height: 1.38;
  font-family: Arial, sans-serif;
}

.rt-header-table,
.rt-bottom-table,
.rt-signature-table,
.rt-mini-table,
.rt-grand-total,
.rt-items-table {
  width: 100%;
  border-collapse: collapse;
}

.rt-company-cell {
  width: 64%;
  vertical-align: top;
  padding: 0 14px 0 0;
}

.rt-meta-cell {
  width: 36%;
  vertical-align: top;
  padding: 0;
}

.rt-company-name,
.rt-party-name,
.rt-document-name {
  color: #1f2937;
  color: var(--rt-text, #1f2937);
  font-weight: 700;
}

.rt-company-name {
  font-size: 18px;
  line-height: 1.15;
}

.rt-address-text,
.rt-legal-line,
.rt-item-desc,
.rt-signature-label,
.rt-cgv-body {
  color: #6b6258;
  color: var(--rt-muted, #6b6258);
}

.rt-address-text {
  margin-top: 8px;
  font-size: 10px;
  line-height: 1.35;
}

.rt-address-text div {
  margin: 0;
  padding: 0;
}

.rt-legal-line {
  margin-top: 8px;
  font-size: 9px;
  line-height: 1.3;
}

.rt-meta-card,
.rt-card {
  border: 1px solid #eadfce;
  border-color: var(--rt-border, #eadfce);
  border-radius: 14px;
  background: #fffdf9;
  background: var(--rt-bg, #fffdf9);
}

.rt-meta-card {
  padding: 12px 14px;
}

.rt-kicker,
.rt-section-title,
.rt-mini-table td:first-child,
.rt-grand-total td:first-child,
.rt-items-table th {
  color: #9a7b53;
  color: var(--rt-accent, #9a7b53);
  text-transform: uppercase;
  letter-spacing: 0.14em;
}

.rt-kicker,
.rt-section-title {
  font-size: 10px;
  font-weight: 700;
}

.rt-document-name {
  margin-top: 6px;
  font-size: 22px;
  line-height: 1.05;
}

.rt-mini-table {
  margin-top: 8px;
}

.rt-mini-table td,
.rt-grand-total td {
  padding: 7px 0;
  border-bottom: 1px solid #efe5d6;
  border-color: var(--rt-soft-border, #efe5d6);
  font-size: 10px;
  vertical-align: top;
}

.rt-mini-table td:first-child,
.rt-grand-total td:first-child {
  width: 46%;
  font-size: 9px;
  font-weight: 600;
}

.rt-mini-table td:last-child,
.rt-grand-total td:last-child {
  text-align: right;
  color: #1f2937;
  color: var(--rt-text, #1f2937);
  font-weight: 700;
}

.rt-card {
  margin-top: 14px;
  padding: 12px 14px;
}

.rt-client-card {
  page-break-inside: avoid;
}

.rt-items-table {
  margin-top: 14px;
  border: 1px solid #eadfce;
  border-color: var(--rt-border, #eadfce);
  border-radius: 14px;
  overflow: hidden;
}

.rt-items-table th {
  padding: 10px 12px;
  background: #fcfaf6;
  background: var(--rt-bg-soft, #fcfaf6);
  border-bottom: 1px solid #eadfce;
  border-color: var(--rt-border, #eadfce);
  font-size: 9px;
  font-weight: 700;
}

.rt-items-table td {
  padding: 11px 12px;
  border-bottom: 1px solid #efe5d6;
  border-color: var(--rt-soft-border, #efe5d6);
  vertical-align: top;
}

.rt-item-row,
.rt-item-row td,
.rt-item-desc,
.rt-item-desc .ql-editor,
.rt-item-desc p {
  page-break-inside: avoid !important;
  break-inside: avoid !important;
}

.rt-col-idx,
.rt-item-idx {
  width: 32px;
  color: #9a7b53;
  color: var(--rt-accent, #9a7b53);
  font-weight: 700;
  text-align: left;
}

.rt-col-desc {
  text-align: left;
}

.rt-col-qty {
  width: 88px;
  text-align: right;
}

.rt-col-money,
.rt-num {
  width: 110px;
  text-align: right;
}

.rt-item-name {
  font-size: 11px;
  line-height: 1.25;
  font-weight: 700;
  color: #1f2937;
  color: var(--rt-text, #1f2937);
}

.rt-item-desc {
  margin-top: 4px;
  font-size: 10px;
  line-height: 1.35;
}

.rt-item-desc .ql-editor,
.rt-item-desc p,
.rt-item-desc div,
.rt-item-desc ul,
.rt-item-desc ol,
.rt-item-desc li {
  margin: 0 !important;
  padding: 0 !important;
  overflow: visible !important;
  max-height: none !important;
}

.rt-half-cell {
  width: 50%;
  vertical-align: top;
  padding: 0;
}

.rt-bottom-table td:first-child {
  padding-right: 7px;
}

.rt-bottom-table td:last-child {
  padding-left: 7px;
}

.rt-bank-card,
.rt-total-card,
.rt-signature-card {
  page-break-inside: avoid;
}

.rt-grand-total {
  margin-top: 10px;
}

.rt-grand-total td {
  padding: 12px 14px;
  border-bottom: 0;
  border: 1px solid #eadfce;
  border-color: var(--rt-border, #eadfce);
  background: #f8f1e5;
  background: var(--rt-bg-total, #f8f1e5);
}

.rt-grand-total td:first-child {
  border-right: 0;
  border-radius: 10px 0 0 10px;
  font-size: 10px;
}

.rt-grand-total td:last-child {
  border-left: 0;
  border-radius: 0 10px 10px 0;
  font-size: 13px;
}

.rt-signature-table {
  margin-top: 10px;
}

.rt-signature-table td {
  width: 50%;
  vertical-align: top;
}

.rt-signature-table td:first-child {
  padding-right: 7px;
}

.rt-signature-table td:last-child {
  padding-left: 7px;
}

.rt-signature-label {
  min-height: 28px;
  font-size: 10px;
  line-height: 1.35;
}

.rt-signature-space {
  height: 54px;
  margin-top: 8px;
  border: 1px dashed #eadfce;
  border-color: var(--rt-border, #eadfce);
  border-radius: 10px;
  background: #ffffff;
}

.rt-cgv-page {
  page-break-before: always;
  break-before: page;
}

.rt-cgv-card {
  margin-top: 0;
  padding: 12px 13px 10px !important;
  page-break-inside: auto;
}

.rt-cgv-body {
  margin-top: 6px;
  font-size: 8.4px;
  line-height: 1.12;
}

.rt-cgv-body,
.rt-cgv-body .ql-editor,
.rt-cgv-body p,
.rt-cgv-body div,
.rt-cgv-body ul,
.rt-cgv-body ol,
.rt-cgv-body li {
  overflow: visible !important;
  max-height: none !important;
}

.rt-cgv-body .ql-editor,
.rt-cgv-body p,
.rt-cgv-body div,
.rt-cgv-body ul,
.rt-cgv-body ol,
.rt-cgv-body li {
  margin: 0 0 2px !important;
  padding: 0 !important;
}

html:
{% macro fmt_identifier(value) -%}
  {%- set clean = (value or "") | replace(" ", "") -%}
  {%- if clean|length == 14 -%}
    {{ clean[:3] }} {{ clean[3:6] }} {{ clean[6:9] }} {{ clean[9:] }}
  {%- elif clean|length == 9 -%}
    {{ clean[:3] }} {{ clean[3:6] }} {{ clean[6:] }}
  {%- else -%}
    {{ value or "" }}
  {%- endif -%}
{%- endmacro %}

{% macro render_address(address) -%}
  {% if address.address_line1 %}<div>{{ address.address_line1 }}</div>{% endif %}
  {% if address.address_line2 %}<div>{{ address.address_line2 }}</div>{% endif %}
  {% if address.pincode or address.city %}
    <div>{{ address.pincode or "" }}{% if address.pincode and address.city %} {% endif %}{{ address.city or "" }}</div>
  {% endif %}
  {% if not (address.pincode or address.city) and address.county %}<div>{{ address.county }}</div>{% endif %}
  {% if address.state and address.state != address.city %}<div>{{ address.state }}</div>{% endif %}
  {% if address.country %}<div>{{ address.country }}</div>{% endif %}
{%- endmacro %}

{% macro legal_line(tax_id, siret, siren) -%}
  {% set values = [] %}
  {% if tax_id %}{% set _ = values.append("TVA " ~ tax_id) %}{% endif %}
  {% if siret %}{% set _ = values.append("SIRET " ~ fmt_identifier(siret)) %}{% endif %}
  {% if siren %}{% set _ = values.append("SIREN " ~ fmt_identifier(siren)) %}{% endif %}
  {% if values %}<div class="rt-legal-line">{{ values | join(" · ") }}</div>{% endif %}
{%- endmacro %}

{% set company = frappe.db.get_value(
  "Company",
  doc.company,
  ["company_name", "siret", "tax_id", "email", "phone_no", "website"],
  as_dict=True,
) or {} %}

{% set company_address = frappe.db.get_value(
  "Address",
  doc.company_address,
  ["address_line1", "address_line2", "city", "county", "state", "pincode", "country", "phone", "email_id"],
  as_dict=True,
) if doc.company_address else {} %}

{% set client = frappe.db.get_value(
  "Customer",
  doc.party_name,
  ["tax_id", "siret", "siren"],
  as_dict=True,
) if doc.quotation_to == "Customer" and doc.party_name else {} %}

{% set client_address = frappe.db.get_value(
  "Address",
  doc.customer_address,
  ["address_line1", "address_line2", "city", "county", "state", "pincode", "country", "phone", "email_id"],
  as_dict=True,
) if doc.customer_address else {} %}

{% set bank_accounts = frappe.db.get_all(
  "Bank Account",
  filters={"company": doc.company, "is_company_account": 1},
  fields=["bank", "iban", "bank_account_no"],
  limit=1,
) %}
{% set bank_account = bank_accounts[0] if bank_accounts else {} %}

{% set bank = frappe.db.get_value(
  "Bank",
  bank_account.bank,
  ["bank_name", "swift_number"],
  as_dict=True,
) if bank_account and bank_account.bank else {} %}

{% set bank_links = frappe.db.get_all(
  "Dynamic Link",
  filters={"link_doctype": "Bank", "link_name": bank_account.bank, "parenttype": "Address"},
  fields=["parent"],
  limit=1,
) if bank_account and bank_account.bank else [] %}

{% set bank_address = frappe.db.get_value(
  "Address",
  bank_links[0].parent,
  ["address_line1", "address_line2", "city", "pincode", "country"],
  as_dict=True,
) if bank_links else {} %}

<section class="rt-print">
  <table class="rt-header-table">
    <tr>
      <td class="rt-company-cell">
        <div class="rt-company-name">{{ company.company_name or doc.company }}</div>
        <div class="rt-address-text">
          {{ render_address(company_address) }}
          {% if company.phone_no or company_address.phone %}<div>{{ company.phone_no or company_address.phone }}</div>{% endif %}
          {% if company.email or company_address.email_id %}<div>{{ company.email or company_address.email_id }}</div>{% endif %}
          {% if company.website %}<div>{{ company.website }}</div>{% endif %}
        </div>
        {{ legal_line(company.tax_id, company.siret, None) }}
      </td>
      <td class="rt-meta-cell">
        <div class="rt-meta-card">
          <div class="rt-kicker">DEVIS</div>
          <div class="rt-document-name">{{ doc.name }}</div>
          <table class="rt-mini-table">
            <tr><td>Date</td><td>{{ doc.get_formatted("transaction_date") }}</td></tr>
            {% if doc.valid_till %}<tr><td>Validité</td><td>{{ doc.get_formatted("valid_till") }}</td></tr>{% endif %}
            {% if doc.po_no %}<tr><td>Réf. client</td><td>{{ doc.po_no }}</td></tr>{% endif %}
          </table>
        </div>
      </td>
    </tr>
  </table>

  <div class="rt-card rt-client-card">
    <div class="rt-section-title">Client</div>
    <div class="rt-party-name">{{ doc.customer_name or doc.party_name or doc.name }}</div>
    <div class="rt-address-text">
      {{ render_address(client_address) }}
      {% if client_address.phone %}<div>{{ client_address.phone }}</div>{% endif %}
      {% if client_address.email_id %}<div>{{ client_address.email_id }}</div>{% endif %}
    </div>
    {{ legal_line(client.tax_id, client.siret, client.siren) }}
  </div>

  <table class="rt-items-table">
    <thead>
      <tr>
        <th class="rt-col-idx">#</th>
        <th class="rt-col-desc">Désignation</th>
        <th class="rt-col-qty">Qté</th>
        <th class="rt-col-money">PU HT</th>
        <th class="rt-col-money">Montant HT</th>
      </tr>
    </thead>
    <tbody>
      {% for row in doc.items or [] %}
      <tr class="rt-item-row">
        <td class="rt-item-idx">{{ row.idx }}</td>
        <td class="rt-item-desc-cell">
          <div class="rt-item-name">{{ row.item_name or row.item_code }}</div>
          {% if row.description %}<div class="rt-item-desc">{{ row.description }}</div>{% endif %}
        </td>
        <td class="rt-num">{{ row.get_formatted("qty") }}{% if row.uom or row.stock_uom %} {{ row.uom or row.stock_uom }}{% endif %}</td>
        <td class="rt-num">{{ row.get_formatted("rate", doc) }}</td>
        <td class="rt-num">{{ row.get_formatted("amount", doc) }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>

  <table class="rt-bottom-table">
    <tr>
      <td class="rt-half-cell">
        <div class="rt-card rt-bank-card">
          <div class="rt-section-title">Coordonnées bancaires</div>
          <div class="rt-party-name">{{ bank.bank_name or bank_account.bank or "Banque" }}</div>
          <table class="rt-mini-table rt-bank-table">
            {% if bank_account.iban or bank_account.bank_account_no %}<tr><td>IBAN</td><td>{{ bank_account.iban or bank_account.bank_account_no }}</td></tr>{% endif %}
            {% if bank.swift_number %}<tr><td>BIC</td><td>{{ bank.swift_number }}</td></tr>{% endif %}
          </table>
          <div class="rt-address-text rt-bank-address">{{ render_address(bank_address) }}</div>
        </div>
      </td>
      <td class="rt-half-cell">
        <div class="rt-card rt-total-card">
          <div class="rt-section-title">Synthèse</div>
          <table class="rt-mini-table rt-total-table">
            <tr><td>Total HT</td><td>{{ doc.get_formatted("net_total") }}</td></tr>
            {% for tax in doc.taxes or [] %}
              {% if tax.tax_amount %}<tr><td>{{ tax.description or tax.account_head or "Taxe" }}</td><td>{{ tax.get_formatted("tax_amount", doc) }}</td></tr>{% endif %}
            {% endfor %}
          </table>
          <table class="rt-grand-total"><tr><td>Total TTC</td><td>{{ doc.get_formatted("grand_total") }}</td></tr></table>
        </div>
      </td>
    </tr>
  </table>

  <div class="rt-card rt-signature-card">
    <div class="rt-section-title">Bon pour accord</div>
    <table class="rt-signature-table">
      <tr>
        <td>
          <div class="rt-signature-label">Date, nom, fonction</div>
          <div class="rt-signature-space"></div>
        </td>
        <td>
          <div class="rt-signature-label">Signature précédée de la mention « Bon pour accord »</div>
          <div class="rt-signature-space"></div>
        </td>
      </tr>
    </table>
  </div>

  {% if doc.terms %}
  <section class="rt-cgv-page">
    <div class="rt-card rt-cgv-card">
      <div class="rt-section-title">Conditions & CGV</div>
      <div class="rt-cgv-body">{{ doc.terms }}</div>
    </div>
  </section>
  {% endif %}
</section>
